import type { LaneMeta, MidiEvent, Pattern } from './types.js';
import { euclid, lcm } from './groove-math.ts';
// Engine ground truth. Regenerated by scripts/generate-presets-json.mjs during
// site prebuild. Hand edits are overwritten — fix the C++ preset factory or the
// emitter instead.
import presetsRaw from '../generated/presets.json' with { type: 'json' };

// Emitter contract — see engine/tools/emit_presets.cpp for the writer side.
interface JsonLane {
  laneIndex: number;
  noteNumber: number;
  roleLabel: string;
  role: string;
  cycleSteps: number;
  subdivision: number;
  stepLen: number;
  hits: number;
  rotation: number;
  velocity: number;
  probability: number;
}
interface JsonPreset {
  index: number;
  name: string;
  description: string;
  activeLaneCount: number;
  notesInBar: number;
  seed: number;
  lanes: JsonLane[];
}
interface JsonSchema {
  schemaVersion: number;
  presetCount: number;
  presets: JsonPreset[];
}

const PRESETS = presetsRaw as JsonSchema;
const PRESETS_BY_ENGINE_NAME = new Map<string, JsonPreset>(
  PRESETS.presets.map((p) => [p.name, p]),
);

const TICKS_PER_BEAT = 4;
const TICKS_PER_BAR = TICKS_PER_BEAT * 4;
const MAX_DRIFT_BARS = 256;

