// --- Rendering primitives (unchanged shape; now fed by JSON) ---

interface LaneSpec {
  label: string;
  role: string;
  color: string;
  note: number;
  steps: number;
  stepLen: number;
  hits: number;
  velocity: number;
  rot: number;
  driftStepsPerBar: number;
}

interface PatternSpec {
  bpm: number;
  lanes: LaneSpec[];
}

// Smallest positive N such that floor(N * |drift|) is a positive multiple of
// steps — how many 4-beat bars drift needs to return a lane to its start.
function driftPeriodBars(steps: number, drift: number): number {
  if (drift === 0) return 1;
  const abs = Math.abs(drift);
  for (let n = 1; n <= MAX_DRIFT_BARS; n++) {
    const shift = Math.floor(n * abs);
    if (shift > 0 && shift % steps === 0) return n;
  }
  return MAX_DRIFT_BARS;
}

function laneEvents(
  laneIdx: number,
  lane: LaneSpec,
  totalTicks: number,
): MidiEvent[] {
  const hitsArr = euclid(lane.hits, lane.steps);
  const staticRot = lane.rot;
  const drift = lane.driftStepsPerBar;
  const steps = lane.steps;
  const events: MidiEvent[] = [];
  for (let tick = 0; tick < totalTicks; tick += lane.stepLen) {
    const rawStep = (tick / lane.stepLen) % steps;
    const driftSteps =
      drift === 0 ? 0 : Math.floor((tick / TICKS_PER_BAR) * drift);
    const idx = (((rawStep + staticRot + driftSteps) % steps) + steps) % steps;
    if (hitsArr[idx]) {
      events.push({
        beat: tick / TICKS_PER_BEAT,
        note: lane.note,
        velocity: lane.velocity,
        lane: laneIdx,
      });
    }
  }
  return events;
}

function toLaneMeta(specs: LaneSpec[]): LaneMeta[] {
  return specs.map((l) => ({
    label: l.label,
    role: l.role,
    note: l.note,
    color: l.color,
  }));
}

function buildPattern(spec: PatternSpec): Pattern {
  const baseCompositeTicks = spec.lanes.reduce(
    (acc, l) => lcm(acc, l.steps * l.stepLen),
    1,
  );
  const driftCompositeTicks = spec.lanes.reduce((acc, l) => {
    if (l.driftStepsPerBar === 0) return acc;
    return lcm(acc, driftPeriodBars(l.steps, l.driftStepsPerBar) * TICKS_PER_BAR);
  }, 1);
  const totalTicks = lcm(baseCompositeTicks, driftCompositeTicks);
  const events = spec.lanes
    .flatMap((l, i) => laneEvents(i, l, totalTicks))
    .sort((a, b) => a.beat - b.beat);
  return {
    bpm: spec.bpm,
    loopBeats: totalTicks / TICKS_PER_BEAT,
    events,
    lanes: toLaneMeta(spec.lanes),
  };
}

// --- JSON → LaneSpec conversion ---

function capitalize(s: string): string {
  return s.length ? s[0].toUpperCase() + s.slice(1) : s;
}

function laneLabel(
  role: string,
  roleLabel: string,
  priorLabels: string[],
): string {
  const functional = FUNCTIONAL_ROLE_LABELS[role];
  const base =
    functional ?? LABEL_FROM_ROLE_LABEL[roleLabel] ?? capitalize(roleLabel);
  // Disambiguate duplicate labels within a single preset so two identical
  // pattern-A/pattern-B lanes read cleanly.
  const priorCount = priorLabels.filter((l) => l === base).length;
  return priorCount === 0 ? base : `${base} ${priorCount + 1}`;
}

function jsonLaneToSpec(
  lane: JsonLane,
  drift: number | undefined,
  priorLabels: string[],
): LaneSpec {
  return {
    label: laneLabel(lane.role, lane.roleLabel, priorLabels),
    role: lane.roleLabel,
    color: HUE[lane.roleLabel] ?? HUE.perc,
    note: lane.noteNumber,
    steps: lane.cycleSteps,
    stepLen: lane.stepLen,
    hits: lane.hits,
    velocity: lane.velocity,
    rot: lane.rotation,
    driftStepsPerBar: drift ?? 0,
  };
}

function jsonPresetToSpec(preset: JsonPreset, engineName: string): PatternSpec {
  const drifts = DRIFT_OVERRIDES[engineName];
  const specs: LaneSpec[] = [];
  const priorLabels: string[] = [];
  preset.lanes.forEach((lane, idx) => {
    const spec = jsonLaneToSpec(lane, drifts?.[idx], priorLabels);
    priorLabels.push(spec.label);
    specs.push(spec);
  });
  return {
    bpm: PRESET_BPM[engineName] ?? 120,
    lanes: specs,
  };
}

// --- Resolution ---

// A display name that starts with 'Factory: ' resolves to its bare engine
// counterpart; otherwise the display name IS the engine name.
function engineNameFor(displayName: string): string | null {
  if (PRESETS_BY_ENGINE_NAME.has(displayName)) return displayName;
  const prefix = 'Factory: ';
  if (displayName.startsWith(prefix)) {
    const bare = displayName.slice(prefix.length);
    if (PRESETS_BY_ENGINE_NAME.has(bare)) return bare;
  }
  return null;
}

export interface ResolvedPreset {
  engineName: string;
  displayName: string;
  notesInBar: number;
  bpm: number;
  lanes: LaneMeta[];
}

// Look up a chapter/factory name and return the engine-resolved preset. Used
// by the card runtime and the (upcoming) preset-consistency Playwright gate to
// prove card ↔ WASM-host agreement on lane structure per chapter.
export function resolvePreset(name: string): ResolvedPreset | null {
  const displayName = resolvePresetName(name);
  if (!displayName) return null;
  const engineName = engineNameFor(displayName);
  if (!engineName) return null;
  const preset = PRESETS_BY_ENGINE_NAME.get(engineName);
  if (!preset) return null;
  const spec = jsonPresetToSpec(preset, engineName);
  return {
    engineName,
    displayName,
    notesInBar: preset.notesInBar,
    bpm: spec.bpm,
    lanes: toLaneMeta(spec.lanes),
  };
}

export function getPatternForPreset(name: string): Pattern | null {
  const displayName = resolvePresetName(name);
  if (!displayName) return null;
  const engineName = engineNameFor(displayName);
  if (!engineName) return null;
  const preset = PRESETS_BY_ENGINE_NAME.get(engineName);
  if (!preset) return null;
  return buildPattern(jsonPresetToSpec(preset, engineName));
}

// Resolve a name into its canonical display name (with 'Factory: ' preserved
// when the input goes through the alias map). Returns null when the name is
// neither a known display name nor a chapter alias.
export function resolvePresetName(name: string): string | null {
  if (DISPLAY_NAME_SET.has(name)) return name;
  const aliased = CHAPTER_ALIASES[name];
  if (aliased && DISPLAY_NAME_SET.has(aliased)) return aliased;
  return null;
}

export function listPresetNames(): string[] {
  return [...DISPLAY_NAMES];
}

export function listChapterAliases(): string[] {
  return Object.keys(CHAPTER_ALIASES);
}
